mapper.select:
select id, policy_id, content, cast(metadata as text) as metadata_json, created_at, updated_at from lego_memory_items where policy_id = #{policyId}
and content ilike '%' || #{q} || '%'
order by coalesce(updated_at, created_at) desc, created_at desc limit #{limit}

mapper.update:
update lego_memory_items
set updated_at = now()
where id = #{id}

mapper.delete:
delete
from lego_memory_items
where id = #{itemId}
  and policy_id = #{policyId}
